diff --git a/llvm/lib/Target/SystemZ/SystemZTargetTransformInfo.cpp b/llvm/lib/Target/SystemZ/SystemZTargetTransformInfo.cpp
index e44777c5c485..6d5fce2b25ef 100644
--- a/llvm/lib/Target/SystemZ/SystemZTargetTransformInfo.cpp
+++ b/llvm/lib/Target/SystemZ/SystemZTargetTransformInfo.cpp
@@ -780,6 +780,16 @@ InstructionCost SystemZTTIImpl::getCastInstrCost(unsigned Opcode, Type *Dst,
   unsigned SrcScalarBits = Src->getScalarSizeInBits();

   if (!Src->isVectorTy()) {
+    if (Dst->isVectorTy()) {
+      // Handle scalar-to-vector cast.
+      // Scalar-to-vector cast: estimate cost based on scalarization overhead.
+      auto *DstVecTy = dyn_cast<FixedVectorType>(Dst);
+      if (DstVecTy) {
+        unsigned NumElements = DstVecTy->getNumElements();
+        return NumElements * BaseT::getCastInstrCost(Opcode, Dst->getScalarType(), Src, CCH, CostKind, I);
+      }
+      return BaseT::getCastInstrCost(Opcode, Dst, Src, CCH, CostKind, I);
+    }
     assert (!Dst->isVectorTy());

     if (Opcode == Instruction::SIToFP || Opcode == Instruction::UIToFP) {
@@ -848,6 +858,12 @@ InstructionCost SystemZTTIImpl::getCastInstrCost(unsigned Opcode, Type *Dst,
     auto *DstVecTy = dyn_cast<FixedVectorType>(Dst);
     if (!DstVecTy) {
       // TODO: tune vector-to-scalar cast.
